Use ASP.NET Core's **`WebApplicationFactory<TEntryPoint>`** — it hosts your app in-memory and gives you an `HttpClient` wired directly to it (no real port needed).

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
```

### Example test class

```csharp
using System.Net.Http.Json;
using Microsoft.AspNetCore.Mvc.Testing;
using Xunit;

public class McpIntegrationTests
    : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2025-03-26",
            body.GetProperty("result")
                .GetProperty("protocolVersion")
                .GetString());
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        // Initialize first (required by MCP)
        await InitializeSession();

        var request = new
        {
            jsonrpc = "2.0",
            id = 2,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var content = body.GetProperty("result")
                         .GetProperty("content")[0];
        Assert.Equal("text", content.GetProperty("type").GetString());
    }

    private async Task InitializeSession() { /* send initialize as above */ }
}
```

### Key points

- **No real port** — `WebApplicationFactory` uses an in-memory test server with a direct `HttpMessageHandler` pipeline.
- **Full middleware stack** — routing, auth, DI, everything runs as in production.
- **Override services** if needed via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))` to swap in test doubles.
- **Streamable HTTP / SSE** — for SSE-based MCP transport, use `factory.CreateDefaultClient()` and read the response stream directly with `HttpCompletionOption.ResponseHeadersRead`.
- Ensure `Program` is accessible (add `public partial class Program { }` to your entry point if using top-level statements).
